import{c as e,Q as r,j as a,m as o}from"./chunks/framework.BXc4yaFE.js";const c=JSON.parse('{"title":"Your Agent should use a File System — @trq212","description":"","frontmatter":{"title":"Your Agent should use a File System — @trq212","author":"Thariq（@trq212）","date":"2025-09-22T00:00:00.000Z","source":"https://x.com/trq212/status/1970243253061783669","type":"tweet"},"headers":[],"relativePath":"research/tweets/2025-09-22-@trq212-783669.md","filePath":"research/tweets/2025-09-22-@trq212-783669.md","lastUpdated":1779894392000}'),s={name:"research/tweets/2025-09-22-@trq212-783669.md"};function n(i,t,l,d,h,g){return r(),a("div",null,[...t[0]||(t[0]=[o('<h1 id="your-agent-should-use-a-file-system-—-trq212" tabindex="-1">Your Agent should use a File System — @trq212 <a class="header-anchor" href="#your-agent-should-use-a-file-system-—-trq212" aria-label="Permalink to &quot;Your Agent should use a File System — @trq212&quot;">​</a></h1><p><strong>來源</strong>：<a href="https://x.com/trq212/status/1970243253061783669" target="_blank" rel="noreferrer">https://x.com/trq212/status/1970243253061783669</a><strong>作者</strong>：Thariq（@trq212） <strong>發布日期</strong>：2025-09-22 <strong>收錄日期</strong>：2026-05-16 <strong>類型</strong>：Twitter Note Tweet（is_note_tweet: true） <strong>統計</strong>：1017 likes · 1156 bookmarks · 179191 views <strong>注意</strong>：note tweet 格式，fxtwitter API 僅能取得 intro，全文請至原始連結閱讀</p><hr><h2 id="全文-intro-節錄" tabindex="-1">全文（Intro 節錄） <a class="header-anchor" href="#全文-intro-節錄" aria-label="Permalink to &quot;全文（Intro 節錄）&quot;">​</a></h2><p>Your Agent should use a File System</p><p>This is a hill I will die on. Every agent can use a file system.</p><p>The file system is an elegant way of representing state that your agent could read into context &amp; allowing it to verify its work.</p><p>🧵on why and examples</p><hr><h2 id="tl-dr" tabindex="-1">TL;DR <a class="header-anchor" href="#tl-dr" aria-label="Permalink to &quot;TL;DR&quot;">​</a></h2><p>File system 是 agent 狀態管理的最優解：每個 agent 都應該使用它來讀取 context 並驗證工作成果。</p><h2 id="核心論點-基於-intro" tabindex="-1">核心論點（基於 intro） <a class="header-anchor" href="#核心論點-基於-intro" aria-label="Permalink to &quot;核心論點（基於 intro）&quot;">​</a></h2><ol><li><strong>普遍適用</strong>：每種 agent 都能使用 file system（&quot;This is a hill I will die on&quot;）</li><li><strong>狀態管理</strong>：file system 是表達 agent 狀態的優雅方式，可讀入 context</li><li><strong>驗證工作</strong>：讓 agent 能夠驗證自己的工作成果</li><li><em>(thread 主體被 API 截斷，完整論點需至原始推文)</em></li></ol><h2 id="批判性觀察" tabindex="-1">批判性觀察 <a class="header-anchor" href="#批判性觀察" aria-label="Permalink to &quot;批判性觀察&quot;">​</a></h2><ol><li><strong>內容受限</strong>：fxtwitter API 對 note tweet 只回傳 intro，無法評估完整論點深度</li><li><strong>高 bookmark/view 比</strong>：bookmark rate 高（1156/179191 = 0.65%），表示實用性強</li><li><strong>Claude Code 已有此實踐</strong>：cc-workspace 的 MEMORY.md + research/ 結構已體現此原則</li></ol><hr><h2 id="評分" tabindex="-1">評分 <a class="header-anchor" href="#評分" aria-label="Permalink to &quot;評分&quot;">​</a></h2><table tabindex="0"><thead><tr><th>維度</th><th>分數</th><th>說明</th></tr></thead><tbody><tr><td>A. Workspace 可行動性 (30%)</td><td>8/10</td><td>cc-workspace 已實踐（MEMORY.md/research/），可驗證並強化</td></tr><tr><td>B. 創新性 (20%)</td><td>5/10</td><td>File system 非新概念；但在 agent 脈絡下強調適用性</td></tr><tr><td>C. 證據品質 (20%)</td><td>4/10</td><td>僅有 intro，無法評估完整論證；thread 主體不可訪問</td></tr><tr><td>D. 技術深度 (15%)</td><td>5/10</td><td>受限於截斷；intro 提到「state + verification」但無細節</td></tr><tr><td>E. 泛化性 (15%)</td><td>9/10</td><td>適用所有 agent 開發，不限特定平台</td></tr><tr><td><strong>加權總分</strong></td><td><strong>6.30/10</strong></td><td>8×0.3 + 5×0.2 + 4×0.2 + 5×0.15 + 9×0.15 = 2.40+1.00+0.80+0.75+1.35</td></tr></tbody></table><p><strong>整合決策</strong>：Rule <strong>理由</strong>：「每個 agent 都應使用 file system」是通用原則，可加入 <code>.claude/rules/</code> 或 agent 設計規範；分數 &gt; 6 但核心是通用原則</p>',19)])])}const m=e(s,[["render",n]]);export{c as __pageData,m as default};
